import type { NewDropdownMenuProps } from ':components/NewDropdownMenu';
import type { FocusEvent } from 'react';
import { useCallback, useEffect, useRef, useState } from 'react';

import type { DateValue, SingleDateValue } from './DatePicker.types';
import type { DatePickerADT, UseDatePickerProps } from './useDatePicker.types';
import { EMPTY_DATE, formatValue, getInputValue, ISO_FORMAT_PATTERN, isFilledDate, isRangeMode } from './utils';

const areDateValuesEqual = (a: DateValue, b: DateValue): boolean => {
	if (typeof a === 'string' && typeof b === 'string') {
		return a === b;
	}

	if (Array.isArray(a) && Array.isArray(b)) {
		if (a.length !== b.length) {
			return false;
		}
		return a.every((item, index) => item === b[index]);
	}

	return false;
};

export const useDatePicker = ({
	value,
	minDate,
	maxDate,
	onChange,
	onOpen,
	onClose,
	onFocus,
	onSaveClick,
	mode,
	multiselect,
	disabledStartDate,
	disabledEndDate,
	prevValue,
	enableTimePicker,
	timeZone,
	datepickerRef,
	mobileView,
	dropdownClassName,
	onBlur,
	overlayScroll,
	shouldRenderOverlay,
	overlayClassName,
	alignDropDown,
}: UseDatePickerProps): DatePickerADT => {
	const [isOpen, setIsOpen] = useState<boolean>(false);
	const isInternalChangeRef = useRef(false);

	const [inputValue, setInputValue] = useState<DateValue>(formatValue(value, enableTimePicker, timeZone, mode));

	useEffect(() => {
		const newInputValue = formatValue(value, enableTimePicker, timeZone, mode);
		if (isInternalChangeRef.current) {
			isInternalChangeRef.current = false;
			return;
		}
		setInputValue(prevInputValue =>
			areDateValuesEqual(prevInputValue, newInputValue) ? prevInputValue : newInputValue,
		);
	}, [value, enableTimePicker, mode, timeZone]);

	const open = useCallback(() => {
		setIsOpen(true);
		onOpen?.();
	}, [onOpen]);

	const close = useCallback(() => {
		setIsOpen(false);

		onClose?.();
	}, [onClose]);

	const toggle = useCallback(() => {
		setIsOpen(prev => !prev);
		isOpen ? onClose?.() : onOpen?.();
	}, [isOpen, onClose, onOpen]);

	const selectDate = useCallback(
		(date: DateValue) => {
			if (mode === 'single') {
				onChange(date);

				const updatedInputValue = getInputValue(date, enableTimePicker, timeZone);
				setInputValue(updatedInputValue);
			}

			if (mode === 'single' && !onSaveClick && !enableTimePicker) {
				close();
			}

			if (mode === 'range') {
				onChange(date);

				const updatedInputValue = getInputValue(date, enableTimePicker, timeZone);
				setInputValue(updatedInputValue);
			}

			const isFilledValue = isFilledDate(date, {
				pattern: ISO_FORMAT_PATTERN,
			});

			if (mode === 'range' && isFilledValue && !onSaveClick && !enableTimePicker) {
				close();
			}

			if (mode === 'rangeSplit' && multiselect) {
				onChange(date);
				return;
			}

			if (mode === 'rangeSplit' && isRangeMode(date) && isRangeMode(prevValue)) {
				const [startDate, endDate] = date;

				const setDate = (startDate: SingleDateValue, endDate: SingleDateValue): void => {
					setInputValue([
						getInputValue(startDate, enableTimePicker, timeZone),
						getInputValue(endDate, enableTimePicker, timeZone),
					]);
					onChange([startDate, endDate]);
				};

				if (disabledStartDate) {
					const [prevStartDate] = prevValue || date;
					setDate(prevStartDate, isFilledValue ? endDate : startDate);
					close();
					return;
				}

				if (disabledEndDate) {
					const [, prevEndDate] = prevValue || date;
					setDate(startDate, prevEndDate);
					close();
					return;
				}

				if (isFilledValue) {
					setDate(startDate, endDate);
					close();
				} else {
					setDate(startDate, EMPTY_DATE);
				}
			}
		},
		[close, disabledEndDate, disabledStartDate, enableTimePicker, mode, multiselect, onChange, onSaveClick, prevValue],
	);

	const clearDate = useCallback(() => {
		// setValue(isRangeMode(value) ? ['', ''] : '');
		// onChange?.(isRangeMode(value) ? ['', ''] : '');
	}, [onChange]);

	const setMinDate = useCallback((date: DateValue) => {
		// Реализуйте установку минимальной даты
	}, []);

	const setMaxDate = useCallback((date: DateValue) => {
		// Реализуйте установку максимальной даты
	}, []);

	const validateDate = useCallback(
		(date: DateValue): boolean =>
			// Реализуйте валидацию даты
			true,
		[],
	);

	const formatDate = useCallback(
		(date: DateValue): string => getInputValue(date, enableTimePicker, timeZone),
		[enableTimePicker, timeZone],
	);

	const handleChange = (value: DateValue): void => {
		// Устанавливаем флаг, что это внутреннее изменение
		isInternalChangeRef.current = true;
		onChange?.(value);
	};

	const handleInputFocus = (event: FocusEvent<HTMLInputElement>): void => {
		if (!isOpen) {
			open();
		}

		onFocus?.(event);
	};

	const dropdownMenuProps: NewDropdownMenuProps = {
		targetElement: datepickerRef,
		align: alignDropDown,
		// клик вне дропдауна должен закрыть только в десктопном варианте
		onOutsideClick: mobileView ? null : close,
		isOpen,
		handleSetOpen: setIsOpen,
		className: dropdownClassName,
		widthMode: 'widthContent',
		onBlur,
		verticalOffset: 1,
		overlayScroll,
		shouldRenderOverlay,
		overlayClassName,
	};

	const handleInputBlur = (event: FocusEvent<HTMLInputElement>): void => {
		onBlur?.(event);

		if (mode === 'range') {
			onClose?.();
		}
	};

	return {
		isOpen,
		inputValue,
		open,
		close,
		toggle,
		selectDate,
		validateDate,
		formatDate,
		clearDate,
		setMinDate,
		setMaxDate,
		setIsOpen,
		setInputValue,
		handleChange,
		handleInputFocus,
		handleInputBlur,
		dropdownMenuProps,
	};
};
